// Auto-generated pixel-art product/tank icons (base64 PNG data-uris) for ห้วยบอนแก๊ส app.
// Loaded as a plain classic <script> before the main app script so PRODUCT_ICONS etc. are global.
const PRODUCT_ICONS = {
  op_milk: 'data:image/png;base64,',
  op_showerhead: 'data:image/png;base64,',
  op_frame4kg: 'data:image/png;base64,',
  op_valve: 'data:image/png;base64,',
  op_regulator: 'data:image/png;base64,',
  op_hose: 'data:image/png;base64,',
  op_clamp: 'data:image/png;base64,',
  op_tank15_new_regular: 'data:image/png;base64,',
  op_tank15_new_ptt: 'data:image/png;base64,',
  op_tank4_regular: 'data:image/png;base64,',
  op_tank4_ptt: 'data:image/png;base64,',
  op_stove_torch: 'data:image/png;base64,',
  op_stove_double: 'data:image/png;base64,',
  op_stove_single: 'data:image/png;base64,',
  tank_regular_15: 'data:image/png;base64,',
  tank_ptt_15: 'data:image/png;base64,',
  tank_regular_7: 'data:image/png;base64,',
  tank_ptt_7: 'data:image/png;base64,',
  tank_regular_4: 'data:image/png;base64,',
  tank_ptt_4: 'data:image/png;base64,',
  tank_regular_48: 'data:image/png;base64,',
  tank_ptt_48: 'data:image/png;base64,',
  tank_regular_generic: 'data:image/png;base64,',
  tank_ptt_generic: 'data:image/png;base64,',
  op_igniter: 'data:image/png;base64,',
};
const PRODUCT_ID_ICON_KEY = {
  op_milk: 'op_milk',
  op_showerhead: 'op_showerhead',
  op_frame4kg: 'op_frame4kg',
  op_valve: 'op_valve',
  op_regulator: 'op_regulator',
  op_hose: 'op_hose',
  op_clamp: 'op_clamp',
  op_tank15_regular: 'op_tank15_new_regular',
  op_tank15_ptt: 'op_tank15_new_ptt',
  op_tank4_regular: 'op_tank4_regular',
  op_tank4_ptt: 'op_tank4_ptt',
  op_stove_torch: 'op_stove_torch',
  op_stove_double: 'op_stove_double',
  op_stove_single: 'op_stove_single',
  op_igniter: 'op_igniter',
};
// returns a base64 data-uri pixel-art icon for a given gas size+brand. Pass size='' or omit it for a
// generic (sizeless) tank icon of that brand. Falls back to the generic icon if a specific size isn't found.
function tankIconSrc(brand, size){
  const b = brand==='ptt'?'ptt':'regular';
  const genericKey = 'tank_' + b + '_generic';
  if(!size) return PRODUCT_ICONS[genericKey] || '';
  const key = 'tank_' + b + '_' + size;
  return PRODUCT_ICONS[key] || PRODUCT_ICONS[genericKey] || '';
}
// returns a base64 data-uri pixel-art icon for a non-gas otherProducts catalog id, or '' if unavailable.
// checks the product's own custom-uploaded icon first (state.otherProducts[].customIcon, set via the
// "เพิ่มสินค้า"/แก้ไข form's image upload) before falling back to the built-in mapped artwork.
function productIconSrc(productId){
  if(typeof state !== 'undefined' && state && Array.isArray(state.otherProducts)){
    const product = state.otherProducts.find(p=>p.id===productId);
    if(product && product.customIcon) return product.customIcon;
  }
  const key = PRODUCT_ID_ICON_KEY[productId];
  return key ? (PRODUCT_ICONS[key] || '') : '';
}
// small <img> helper, returns '' (renders nothing) if src is missing so callers can safely inline it
function iconImgHtml(src, size, extraStyle){
  size = size || 32;
  if(!src) return '';
  return '<img src="' + src + '" style="width:' + size + 'px;height:' + size + 'px;image-rendering:pixelated;border-radius:6px;vertical-align:middle;flex-shrink:0;' + (extraStyle||'') + '">';
}
